class Solution:
    def countSubarrays(self, nums, k: int) -> int:
        n = len(nums)
        count = 0
        for i in range(n):
            val = nums[i]
            for j in range(i, n):
                val &= nums[j]
                if val == k:
                    count += 1
                elif val < k:
                    break
        return count

