class Solution:
    def countSubarrays(self, nums, k: int) -> int:
        count = 0
        # List of (and_value, freq)
        prev = []
        for x in nums:
            curr = [(x, 1)]
            for av, cnt in prev:
                nv = av & x
                if curr[-1][0] == nv:
                    curr[-1] = (nv, curr[-1][1] + cnt)
                else:
                    curr.append((nv, cnt))
            for av, cnt in curr:
                if av == k:
                    count += cnt
            prev = curr
        return count

