var countSubarrays = function(nums, k) {
    let count = 0;
    let prev = [];
    for (const x of nums) {
        const curr = [[x, 1]];
        for (const [av, cnt] of prev) {
            const nv = av & x;
            if (curr[curr.length - 1][0] === nv) {
                curr[curr.length - 1][1] += cnt;
            } else {
                curr.push([nv, cnt]);
            }
        }
        for (const [av, cnt] of curr) {
            if (av === k) count += cnt;
        }
        prev = curr;
    }
    return count;
};
